#define PI 3.1415926535897932

long M = 2147483647;
int A = 1103515245;
int C = 12345;

double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return (double)newValue;
    else
        return (double)(newValue + 1);
}

double randu(int * seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

double randn(int * seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

void strelDisk(int * disk, int radius) {
    int diameter = radius * 2 - 1;
    int x, y;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) + pow((double)(y - radius + 1), 2));
            if (distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void getneighbors(int * se, int numOnes, int * neighbors, int radius) {
    int x, y;
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(unsigned char * I, int IszX, int IszY, int Nfr, int * seed) {
    int k;
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    int xk, yk, pos;
    for (k = 1; k < Nfr; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size)
            pos = 0;
        I[pos] = 1;
    }

    int radius = 5;
    int diameter = radius * 2 - 1;
    int * disk = (int *)malloc(diameter * diameter * sizeof(int));
    strelDisk(disk, radius);

    int countOnes = 0;
    int x, y;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            if (disk[x * diameter + y] == 1)
                countOnes++;
        }
    }

    int * objxy = (int *)malloc(countOnes * 2 * sizeof(int));
    getneighbors(disk, countOnes, objxy, radius);

    unsigned char * newMatrix = (unsigned char *)malloc(sizeof(unsigned char) * IszX * IszY * Nfr);

    for (z = 0; z < Nfr; z++) {
        for (x = 0; x < IszX; x++) {
            for (y = 0; y < IszY; y++) {
                if (I[x * IszY * Nfr + y * Nfr + z] == 1) {
                    int startX = x - radius;
                    if (startX < 0) startX = 0;
                    int startY = y - radius;
                    if (startY < 0) startY = 0;
                    int endX = x + radius;
                    if (endX > IszX) endX = IszX;
                    int endY = y + radius;
                    if (endY > IszY) endY = IszY;

                    for (int dx = startX; dx < endX; dx++) {
                        for (int dy = startY; dy < endY; dy++) {
                            double distance = sqrt(pow((double)(dx - x), 2) + pow((double)(dy - y), 2));
                            if (distance < radius)
                                newMatrix[dx * IszY * Nfr + dy * Nfr + z] = 1;
                        }
                    }
                }
            }
        }
    }

    for (x = 0; x < IszX; x++) {
        for (y = 0; y < IszY; y++) {
            for (k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);
    free(disk);
    free(objxy);

    for (x = 0; x < IszX; x++) {
        for (y = 0; y < IszY; y++) {
            for (z = 0; z < Nfr; z++) {
                if (I[x * IszY * Nfr + y * Nfr + z] == 0)
                    I[x * IszY * Nfr + y * Nfr + z] = 100;
                else if (I[x * IszY * Nfr + y * Nfr + z] == 1)
                    I[x * IszY * Nfr + y * Nfr + z] = 228;
            }
        }
    }

    for (x = 0; x < IszX; x++) {
        for (y = 0; y < IszY; y++) {
            for (z = 0; z < Nfr; z++) {
                I[x * IszY * Nfr + y * Nfr + z] = I[x * IszY * Nfr + y * Nfr + z] + (unsigned char)(5 * randn(seed, 0));
            }
        }
    }
}

int findIndex(double * CDF, int lengthCDF, double value) {
    int index = -1;
    int x;
    for (x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

int findIndexBin(double * CDF, int beginIndex, int endIndex, double value) {
    if (endIndex < beginIndex)
        return -1;
    int middleIndex = beginIndex + ((endIndex - beginIndex) / 2);

    if (CDF[middleIndex] >= value) {
        if (middleIndex == 0)
            return middleIndex;
        else if (CDF[middleIndex - 1] < value)
            return middleIndex;
        else if (CDF[middleIndex - 1] == value) {
            while (middleIndex > 0 && CDF[middleIndex - 1] == value)
                middleIndex--;
            return middleIndex;
        }
    }
    if (CDF[middleIndex] > value)
        return findIndexBin(CDF, beginIndex, middleIndex + 1, value);
    return findIndexBin(CDF, middleIndex - 1, endIndex, value);
}

